import { tool } from 'ai';
import { z } from 'zod';

export const rollDieToolWithProgrammaticCalling = tool({
  description: 'Roll a die and return the result.',
  inputSchema: z.object({
    player: z.enum(['player1', 'player2']),
  }),
  providerOptions: {
    anthropic: {
      allowedCallers: ['code_execution_20260120'],
    },
  },
  execute: async ({ player }) => {
    if (player === 'player1') {
      // Simulate a loaded die that slightly skews towards 6
      const r = Math.random();
      if (r < 0.13) return { roll: 1 };
      if (r < 0.26) return { roll: 2 };
      if (r < 0.39) return { roll: 3 };
      if (r < 0.52) return { roll: 4 };
      if (r < 0.65) return { roll: 5 };
      return { roll: 6 };
    } else {
      return { roll: Math.floor(Math.random() * 6) + 1 };
    }
  },
});

import Link from "next/link";
import Image from "next/image";

export default function PostPreviewCondensed({
  title,
  coverImage,
  coverImageAlt,
  excerpt,
  slug,
}) {
  return (
    <div className="col-lg-4 col-md-8 col-sm-10">
      <div className="single-blog">
        {coverImage && (
          <div className="blog-header">
            <Image
              src={coverImage}
              alt={coverImageAlt}
              layout="fill"
              objectFit="cover"
            />
          </div>
        )}
        <div className="blog-body">
          <h5 className="package-name">
            <Link href={`/blog/${slug}`}>{title}</Link>
          </h5>
          <p>{excerpt}</p>
        </div>
        <div className="blog-footer">
          <Link href={`/blog/${slug}`} className="main-btn btn-hover">
            Read More
          </Link>
        </div>
      </div>
    </div>
  );
}

import Avatar from "./avatar";
import Date from "./date";
import CoverImage from "./cover-image";
import Link from "next/link";

export default function HeroPost({
  title,
  coverImage,
  date,
  excerpt,
  author,
  slug,
}) {
  return (
    <section>
      <div className="mb-8 md:mb-16">
        <CoverImage
          title={title}
          responsiveImage={coverImage.responsiveImage}
          slug={slug}
        />
      </div>
      <div className="md:grid md:grid-cols-2 md:gap-x-16 lg:gap-x-8 mb-20 md:mb-28">
        <div>
          <h3 className="mb-4 text-4xl lg:text-6xl leading-tight">
            <Link href={`/posts/${slug}`} className="hover:underline">
              {title}
            </Link>
          </h3>
          <div className="mb-4 md:mb-0 text-lg">
            <Date dateString={date} />
          </div>
        </div>
        <div>
          <p className="text-lg leading-relaxed mb-4">{excerpt}</p>
          <Avatar name={author.name} picture={author.picture} />
        </div>
      </div>
    </section>
  );
}

